), target_creators AS (
  SELECT UNNEST(ARRAY['2891deb2ec62d19dce0514d73ecb699b3432c3cec2699e356737d0e9927ba546','2edcd076f50198e71666684283ecda8569313ce64d8f44429bcc5957e3a0fd97','303ed46f9399cf659f9209967070b055333c3959b6a170e91911030c2ddc73a8','5001fafa23b819c6b8a135f9fdff49e3f5e5088cd42d3560219bebfa05ad89f9','5b62850775a1604de06ef7a977320160f2cc5a2a6ec38c2eb026fc3ca89f495d','6dc6050deb2cbc1c8d7bc2edd05ed4f5bb2e7f3830f5e9caf8008814f381dbab','99456a7792582d1ce80fd7ee5d4e2a47207226d0fb7274a8ab9217239efbc7ed','9adc8044b64dbf35c7263596707aef79a5ccaddb6d717f3aa001603aac0e2a24','ad740a7bec32dca47ff4ab50cb4cc2fd00c0c423e81c3264d2569b807c4869db','b7b0107fb9ce1f0f131f640a21e799361b437903a1c76e57b56542cc9f6b591b','c512835285a4bc47ee9b66837114c81a60e07b8e48f5f88078d6a70bad90add0','d32ea1af79a113479348aff03287c4bc69c3aa715f8d84ea0534c13a7a5e8bd9']::text[]) AS creator_hash
), feeder_rows AS (
  SELECT encode(c.hash,'hex') AS creator_tx_hash, c.id AS creator_tx_id, c.block_id AS creator_block_id, cb.epoch_no AS creator_epoch, cb.time AS creator_time,
         encode(f.hash,'hex') AS feeder_tx_hash, f.id AS feeder_tx_id, f.block_id AS feeder_block_id, fb.epoch_no AS feeder_epoch, fb.time AS feeder_time,
         o.id AS feeder_tx_out_id, o.index AS feeder_out_index, o.value::numeric/1000000 AS feeder_ada,
         EXTRACT(EPOCH FROM (cb.time - fb.time))/3600.0 AS hours_held,
         COALESCE(fin.input_count,0) AS feeder_input_count, COALESCE(fout.output_count,0) AS feeder_output_count,
         COALESCE(fout.total_output_lovelace,0)::numeric/1000000 AS feeder_total_output_ada,
         COALESCE(fout.max_output_lovelace,0)::numeric/1000000 AS feeder_max_output_ada
  FROM tx_out o
  JOIN tx f ON f.id=o.tx_id
  JOIN block fb ON fb.id=f.block_id
  JOIN tx_in i ON i.tx_out_id=o.tx_id AND i.tx_out_index=o.index
  JOIN tx c ON c.id=i.tx_in_id
  JOIN block cb ON cb.id=c.block_id
  LEFT JOIN (SELECT tx_in_id AS tx_id, COUNT(*) AS input_count FROM tx_in GROUP BY tx_in_id) fin ON fin.tx_id=f.id
  LEFT JOIN (SELECT tx_id, COUNT(*) AS output_count, SUM(value) AS total_output_lovelace, MAX(value) AS max_output_lovelace FROM tx_out GROUP BY tx_id) fout ON fout.tx_id=f.id
  WHERE o.id IN (SELECT tx_out_id FROM target_outs) AND encode(c.hash,'hex') IN (SELECT creator_hash FROM target_creators)
)
SELECT * FROM feeder_rows ORDER BY creator_epoch, creator_time, creator_tx_hash, feeder_ada DESC
) TO STDOUT WITH CSV HEADER
